// Initialize reviews in Firestore if collection is empty
export async function initializeReviewsIfEmpty() {
  try {
    const reviewsCol = collection(db, "reviews");
    const q = query(reviewsCol, limit(1));
    const querySnapshot = await getDocs(q);
    
    if (querySnapshot.empty) {
      for (const review of DEFAULT_REVIEWS) {
        await addDoc(reviewsCol, review);
      }
    }
  } catch (error) {
    console.error("Error seeding reviews in Firestore:", error);
  }
}

// Subscribe to live reviews from Firestore
export function subscribeToReviews(callback: (reviews: UserReview[]) => void) {
  // Ensure seed data exists in DB
  initializeReviewsIfEmpty();

  const reviewsCol = collection(db, "reviews");
  const q = query(reviewsCol, orderBy("timestamp", "desc"), limit(12));
  
  return onSnapshot(q, (snapshot) => {
    const reviewsList: UserReview[] = [];
    snapshot.forEach((docSnap) => {
      const data = docSnap.data();
      reviewsList.push({
        id: docSnap.id,
        name: data.name,
        rating: data.rating,
        comment: data.comment,
        businessType: data.businessType || "Negocio Local",
        timestamp: data.timestamp
      });
    });

    if (reviewsList.length > 0) {
      callback(reviewsList);
    } else {
      // Fallback if network or reading fails temporarily
      callback(DEFAULT_REVIEWS.map((r, idx) => ({ ...r, id: `temp-${idx}` })));
    }
  }, (error) => {
    console.error("Error subscribing to reviews:", error);
    // Fallback on error
    callback(DEFAULT_REVIEWS.map((r, idx) => ({ ...r, id: `temp-${idx}` })));
  });
}

// Submit a new review to the 'reviews' collection
export async function submitReview(name: string, rating: number, comment: string, businessType: string) {
  try {
    const reviewsCol = collection(db, "reviews");
    await addDoc(reviewsCol, {
      name: name || "Anónimo",
      rating: rating,
      comment: comment || "",
      businessType: businessType || "Comercio",
      timestamp: new Date()
    });

    // Also update global metrics to keep rating average alive
    const docRef = doc(db, METRICS_DOC_PATH);
    await updateDoc(docRef, {
      ratingsCount: increment(1),
      totalStars: increment(rating)
    });

    return true;
  } catch (error) {
    console.error("Error submitting review to reviews collection:", error);
    return false;
  }
}

